mapper.select:
SELECT DISTINCT r.*, l.code_value AS elementobjectType FROM all_code_data l RIGHT JOIN ( SELECT elemntObject AS elementObject, elemntchname AS elementchname, elemntcode AS elementCode, elemntrule AS elementRule, moddate AS modDate, author AS author, iselemnt AS isElement, sameid AS sameId, createmode AS createMode FROM synlte.ENTITY_ELEMENT ) r ON r.elementobject = l.code_value
(upper(r.elementchname) like upper(concat('%',concat(#{searchText},'%'))))
and iselement in (
#{item}
)
and l.code_text = #{elementObject}
order by ${sort} ${sortOrder}
